export const UNIFESP_2025_QUESTIONS: any[] = [
  { id: "unifesp_2025_001", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Anestesiologia", text: "Mulher, 27 anos de idade, 55 kg e 1,65 m, submetida a raquianestesia e anestesia geral para tratamento cirúrgico de endometriose. Durante avaliação pré-anestésica foi identificado alto risco para náusea e vômito no pós-operatório. Com objetivo de reduzir o risco de ocorrência de complicação no pós-operatório, qual é a conduta mais adequada?", options: ["Anestesia balanceada com propofol, remifentanil e sevoflurano.", "Anestesia inalatória com sevoflurano e óxido nitroso.", "Anestesia combinada com propofol e isoflurano.", "Anestesia venosa total com propofol e remifentanil."], correctIndex: 3 },
  { id: "unifesp_2025_002", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Cirurgia", text: "75 anos de idade, apresenta dor abdominal em cólica de forte intensidade e com 36 horas de evolução, de localização difusa, acompanhado de náuseas e vômitos. Nas últimas 24 horas, nega eliminação de gases e fezes. Exame físico: REG, descorada, FC 90 bpm, PA 150 x 95 mm Hg, temperatura 37,5 °C; abdômen globoso, distendido, ruídos hidroaéreos aumentados, hipertimpanismo difuso e doloroso à palpação, mas sem sinais de irritação peritoneal. A sequência do Rx de abdome em três posições evidenciou estômago e alças intestinal difusamente dilatadas, níveis hidroaéreos e pneumocolangiograma presente. Qual é o diagnóstico mais provável?", options: ["Hérnia interna", "Trombose mesentérica", "Íleo biliar", "Neoplasia colorretal obstrutiva"], correctIndex: 2 },
  { id: "unifesp_2025_003", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Urologia", text: "Homem, 24 anos de idade, é admitido no PS por acidente automobilístico. Exame físico: via aérea pérvia, pneumotórax esquerdo com fratura linear da 3°, 4° e 5° costelas, estável hemodinamicamente, sinais de trauma raquimedular em L3-L4, múltiplas fraturas em membros superiores e inferiores. Exames de imagem: ausência de outras lesões no abdômen e na pelve. Com relação à drenagem da via urinária, qual é a conduta mais adequada?", options: ["Sondagem vesical de demora.", "Cistostomia supra-púbica.", "Cateterismo intermitente.", "Nefrostomia bilateral guiada por radiointervenção."], correctIndex: 0 },
  { id: "unifesp_2025_004", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Cardiologia", text: "Homem, 48 anos de idade, previamente assintomático, comparece ao PS com dor torácica de forte intensidade, em aperto, com início súbito e irradiação para dorso e região interescapular, há 2 horas. Exame físico: sudoreico, FC 100 bpm, PA 190 x 100 mm Hg nos quatro membros, pulsos rítmicos e presença de sopro diastólico suave, 4+/6+, no foco aórtico. Após análise do eletrocardiograma, qual é a conduta mais adequada?", options: ["Cirurgia de emergência", "Angioplastia primária da artéria culpada", "Passagem de balão intra-aórtico", "Trombólise com alteplase"], correctIndex: 0 },
  { id: "unifesp_2025_005", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Cirurgia", text: "Mulher, 47 anos de idade, antecedente de colelitíase, dá entrada no PS com queixa de dor epigástrica há 8 horas. Exame físico: estável hemodinamicamente, com abdômen distendido, doloroso difusamente no andar superior e DB negativa. Exames laboratoriais: leucograma 14.120 células/mm³ (80% de neutrófilos), PCR 32 mcg/dL e amilase 1.340 mcg/dL. Qual é a conduta nutricional mais adequada?", options: ["Dieta oral após melhora da dor e da amilase.", "Dieta oral entre 24 a 48 horas.", "Dieta enteral por sonda pós-pilórica.", "Dieta parenteral por acesso venoso central."], correctIndex: 1 },
  { id: "unifesp_2025_006", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Cirurgia Pediátrica", text: "Um recém-nascido de 48 horas de vida apresenta vômitos biliosos e grande distensão abdominal. Eliminou mecônio 16 horas após o nascimento. Rx abdominal: intensa distensão de alças. Qual é o diagnóstico mais provável?", options: ["Megacólon congênito.", "Atresia jejunal.", "Íleo meconial.", "Obstrução duonenal."], correctIndex: 1 },
  { id: "unifesp_2025_007", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Recém-nascido de 35 semanas de idade gestacional, apresenta desconforto respiratório logo após o nascimento. Ao exame, está cianótico +/4+, com murmúrio vesicular presente bilateralmente com roncos disseminados; sopro sistólico rude no foco aórtico; abdome globoso, distendido, flácido, RHA + e normais, ausência de orifício anal; apresenta escoliose e deformidade em perna e pé à direita. Qual é a conduta inicial mais adequada?", options: ["Ultrassonografia de abdome.", "Ecocardiograma com doppler.", "Tomografia computadorizada de tórax.", "Passagem de sonda nasogástrica."], correctIndex: 3 },
  { id: "unifesp_2025_008", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Cirurgia Plástica", text: "Homem, 18 anos de idade, vítima de acidente por queda de moto, apresenta lesão na face posterior do antebraço direito. Exame físico: lesão de aproximadamente 25 x 7 cm, com sangramento e sujidade local, exposição da musculatura e gordura e sem exposição de vasos, nervos, tendões ou osso. Radiografia: ausência de fraturas. Submeteu-se a lavagem com desbridamento pela equipe da Cirurgia Geral. Após 10 dias, foi solicitada uma interconsulta para a equipe de Cirurgia Plástica. Qual é a conduta mais adequada para a cobertura?", options: ["Enxerto de pele total.", "Enxerto de pele parcial.", "Retalho microcirúrgico.", "Fechamento por segunda intenção."], correctIndex: 1 },
  { id: "unifesp_2025_009", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Cirurgia Vascular", text: "Homem, 78 anos de idade, realizou ultrassonografia abdominal que evidenciou dilatação da aorta abdominal abaixo das artérias renais de 4,5 cm de diâmetro e 10 cm de extensão. Qual é a conduta mais adequada?", options: ["Acompanhamento seriado com ultrassom a cada 6 meses.", "Tratamento endovascular com prótese reta.", "Cirurgia convencional.", "Tratamento endovascular com prótese bifurcada."], correctIndex: 0 },
  { id: "unifesp_2025_010", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Um ensaio clínico randomizado é considerado \"duplo-cego\" quando são mascarados para o desfecho em questão:", options: ["Participantes e equipe.", "Participantes, equipe e avaliadores de desfecho.", "Equipe e avaliadores de desfecho.", "Participantes e avaliadores de desfecho."], correctIndex: 1 },
  { id: "unifesp_2025_011", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Cirurgia", text: "Homem, 70 anos de idade, com doença diverticular do cólon, apresenta-se estável hemodinamicamente, com dor abdominal intensa, febre e leucocitose. A tomografia computadorizada mostra um abscesso pericólico de 5 cm associado a diverticulite aguda. Qual é a conduta inicial mais adequada?", options: ["Antibióticos intravenosos e observação.", "Colectomia segmentar de urgência.", "Cirurgia laparoscópica para drenagem e lavagem peritoneal.", "Drenagem percutânea do abscesso guiada por imagem."], correctIndex: 3 },
  { id: "unifesp_2025_012", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Cirurgia Torácica", text: "Homem, 35 anos de idade, foi submetido à descorticação pulmonar devido empiema pleural em fase fibrinopurulenta. No pós-operatório, permaneceu com febre e a radiografia de tórax mostrou uma coleção pleural septada e única. O débito do dreno permanece com aspecto purulento. Qual é a conduta mais adequada?", options: ["Trocar antibiótico.", "Redrenar o tórax.", "Pleurostomia.", "Aspiração contínua."], correctIndex: 2 },
  { id: "unifesp_2025_013", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Cirurgia Torácica", text: "Homem, 70 anos de idade, apresenta adenocarcinoma em lobo superior do pulmão esquerdo. Durante estadiamento da neoplasia observou-se comprometimento dos linfonodos das cadeias 4 ipsilateral e 7. Não foram identificadas metástases no PET-CT. Qual a conduta mais adequada?", options: ["Tratamento não cirúrgico.", "Lobectomia superior esquerda.", "Pneumonectomia esquerda.", "Segmentectomia esquerda."], correctIndex: 0 },
  { id: "unifesp_2025_014", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Cirurgia Torácica", text: "Mulher, 32 anos, vem ao ambulatório com tubo T devido estenose traqueal. Refere que está com esta órtese há 7 meses. Durante investigação complementar é realizada uma broncoscopia que evidencia estenose fixa, compreendendo 1º e 2º anéis traqueais sem processo inflamatório local. Qual a conduta mais adequada?", options: ["Realizar a troca do tubo T.", "Programar traqueoplastia.", "Corticoterapia.", "Cânula metálica."], correctIndex: 1 },
  { id: "unifesp_2025_015", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Urologia", text: "Homem, 65 anos de idade, apresenta sangramento na urina há 6 meses. Exame físico: BEG, FC 80 bpm, PA 120x80 mm Hg, T 36,5 °C, e abdômen indolor à palpação. Exames: Hb 12,3 d/dL, leucocitos 9.000 células/mm³, plaquetas 170.000/mm³, Na 144 mEq/L, K 4,0 mEq/L, U 30 mg/dL, C 1,2 mg/dL, TGO 30 U/L, TGP 40 U/L, FA 30 U/L, GGT 50 U/L. Ultrassonografia do abdômen: lesão polipoide da bexiga de 3 cm na parede lateral direita, com presença de fluxo ao estudo Doppler. Submeteu-se à ressecção transuretral da lesão vesical. Qual é o diagnóstico mais provável?", options: ["Carcinoma espinocelular.", "Carcinoma urotelial.", "Adenocarcinoma.", "Carcinoma de pequenas células."], correctIndex: 1 },
  { id: "unifesp_2025_016", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Urologia", text: "Homem, 74 anos de idade, apresenta dor abdominal supra-púbica de forte intensidade, com última micção há 16 horas e perda urinária em gotas, em pouco volume. Exame físico: REG, afebril, globo vesical palpável. Exames laboratoriais: C 1,3 mg/dL, U 60 mg/dL, hemograma sem alteração. Realizado sondagem vesical de alívio, com saída de 1.300 mL de urina concentrada, e alivio do desconforto. Qual é a conduta mais adequada?", options: ["Treinar cateterismo intermitente.", "Passagem de sonda vesical de demora.", "Iniciar terapia combinada com alfa-bloqueador e inibidor de 5-alfa-redutase.", "Solicitar estudo urodinâmico."], correctIndex: 1 },
  { id: "unifesp_2025_017", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Medicina Intensiva", text: "Mulher, 62 anos de idade, em estado crítico após sepse grave, necessita de acesso vascular central para administração de medicamentos e monitorização hemodinâmica. Após a punção venosa, a ultrassonografia revela a presença de bolhas de ar entre a agulha de punção e a veia jugular interna. Qual é a conduta mais adequada?", options: ["Aspirar as bolhas de ar com seringa e prosseguir com a inserção do cateter no mesmo sítio.", "Realizar nova punção em outro local, sob orientação ultrassonográfica.", "Injetar contraste venoso sob orientação ultrassonográfica para confirmar a punção correta.", "Abandonar a inserção do acesso por veia jugular interna e considerar o acesso femoral."], correctIndex: 1 },
  { id: "unifesp_2025_018", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Gastroenterologia", text: "Homem, 60 anos de idade, realizou endoscopia digestiva alta por melena sem repercussão hemodinâmica. O laudo apresenta lesão ulcerada bem delimitada de 8 mm na pequena curvatura do antro, com fundo recoberto por fibrina. A biópsia revelou gastrite crônica e presença de Helicobacter pylori. Qual é a conduta mais adequada?", options: ["Nova endoscopia com biópsia.", "Eco-endoscopia.", "Angiotomografia.", "Claritromicina 500 mg e amoxicilina 1 g, de 12/12 horas, por 7 dias."], correctIndex: 0 },
  { id: "unifesp_2025_019", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Otorrinolaringologia", text: "Mulher, 44 anos de idade, apresenta quadro súbito de vertigem rotatória intensa há 3 horas, associada a náuseas, vômitos, sudorese profusa e mal-estar, que pioram à movimentação cefálica. Nega sintomas auditivos associados. Antecedentes: diabetes tipo 1 em uso de insulina, dislipidemia em uso de atorvastatina, hipertensão arterial em uso de anlodipino. Refere cefaleia por abuso de analgésico, em seguimento. Exame físico: PA100x60 mmHg, FC 98 bpm, Sat O2 98% em ar ambiente, dextro 113 mg/dL, REG, descorada (1+/4+), desidratada (2+/4+), eupneica. Nistagmo: espontâneo horizontal para a direita, semi-espontâneo presente ao olhar para a direita (horizontal para a direita) e ao olhar para a esquerda (horizontal para a direita), sendo mais intenso com o olhar para a direita e ausente com o olhar para cima e para baixo. HIT (head impulse test): presença de sacada corretiva ao virar a cabeça para a esquerda. Otoscopia: membranas timpânicas íntegras e translúcidas, meato acústico externo livre. Paciente não tolerou testes de Romberg, Fukuda e manobras posicionais por quadro de vômitos e mal-estar. Qual é o diagnóstico mais provável?", options: ["Migrânea vestibular.", "Acidente Vascular Cerebral.", "Vertigem Posicional Paroxística Benigna.", "Neurite vestibular."], correctIndex: 3 },
  { id: "unifesp_2025_020", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Ortopedia", text: "Homem, 35 anos de idade, vem ao ambulatório de joelho após 3 semanas de acidente de carro no qual sofreu trauma direto no seu joelho esquerdo contra o painel do carro. Refere que na ocasião percebeu grande hematoma, inchaço e dor no joelho. Foi ao pronto socorro e realizou radiografias sem fraturas, sendo recomendado anti-inflamatórios e crioterapia. Exame físico: aumento da translação posterior do joelho esquerdo e deslizamento posterior da tíbia. Qual é o diagnóstico mais provável?", options: ["Lesão do ligamento cruzado posterior.", "Lesão do ligamento cruzado anterior.", "Lesão do ligamento menisco-femoral.", "Lesão do ligamento oblíquo posterior."], correctIndex: 0 },
  { id: "unifesp_2025_021", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Cardiologia", text: "Homem, 65 anos de idade, apresentou dor precordial no domicílio, de forte intensidade, com irradiação para membro superior esquerdo e sudorese, porém só procurou atendimento médico 14 horas após o quadro, quando a dor já havia cessado. O exame cardíaco inicial não mostrou alterações significativas. ECG: supradesnivelamento do segmento ST de aproximadamente 1 mm nas derivações D2, D3 e aVF, com inversão de onda T e onda Q patológica nas mesmas derivações. Após 48 horas, notou-se um sopro holossistólico em ápice, irradiado para axila, associado a hipotensão arterial e má perfusão periférica. Qual é a explicação mais provável para o quadro?", options: ["Ruptura do músculo papilar posterior.", "Ruptura da parede livre de ventrículo esquerdo.", "Comunicação interventricular.", "Insuficiência aórtica."], correctIndex: 0 },
  { id: "unifesp_2025_022", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Endocrinologia", text: "Mulher, 70 anos de idade, com hipertensão, osteoartrose e osteoporose em coluna lombar (T-score -2,9), realiza investigação laboratorial com os seguintes resultados: creatinina = 0,9 mg/dL (VR 0,6 a 1,1 mg/dL), TSH = 3,0 mUI/L (VR 0,44 a 5,4 mUI/L), PTH = 15 pg/mL (VR 22 a 84 pg/mL), cálcio total = 10,7 mg/dL (VR 8,6 a 10,3 mg/dL). Qual medicamento listado abaixo pode causar a alteração laboratorial observada?", options: ["Denosumabe", "Glicocorticoide", "Diurético tiazídico", "Cloroquina"], correctIndex: 2 },
  { id: "unifesp_2025_023", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Medicina Intensiva", text: "Homem, 55 anos de idade, com histórico de doença pulmonar obstrutiva crônica sofre uma parada cardiorrespiratória em atividade elétrica sem pulso enquanto estava na UTI. A equipe inicia as manobras de ressuscitação cardiopulmonar (RCP) imediatamente, mas não há retorno da circulação espontânea após 5 minutos. Durante a ressuscitação, o monitor de capnografia mostra um valor de dióxido de carbono ao final da expiração (ETCO2) de 8 mmHg e a pressão arterial diastólica (PAD) é registrada como 15 mmHg durante as compressões torácicas. Qual deve ser a próxima ação para melhorar a qualidade da RCP?", options: ["Manter as compressões torácicas sem alterações e aumentar a frequência da ventilação por minuto.", "Reduzir o número de compressões, uma vez que os valores de ETCO2 e PAD indicam uma velocidade de compressão excessiva.", "Ajustar a profundidade e frequência das compressões torácicas para aumentar os valores de ETCO2 e PAD.", "Continuar as compressões torácicas sem alterações e administrar uma dose adicional de epinefrina."], correctIndex: 2 },
  { id: "unifesp_2025_024", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Endocrinologia", text: "Mulher, 60 anos de idade, em amenorreia há quatro anos, foi recentemente diagnosticada com anemia e na investigação apresenta os seguintes exames: TSH = 1,97 mUI/mL (VR 0,45 a 4,5 mUI/mL), T4 livre = 0,3 ng/dL (VR 0,9 a 1,8 ng/dL), FSH = 4,0 mUI/mL (VR 3,6 a 16,6 mUI/mL), LH = 1,6 mUI/mL (VR 1,1 a 11,1 mUI/mL), cortisol = 6,6 mcg/dL (VR 5,0 a 25 mcg/dL), ACTH = 12,6 pg/mL (VR < 46 pg/mL), IGF-1 = 64 ng/mL (VR 83 a 241 ng/mL), prolactina = 80 ng/dL (VR 5 a 25 ng/dL). A ressonância magnética da sela túrcica evidenciou lesão hipofisária de 3,5 x 2,8 x 3,1 cm em região selar compatível com adenoma hipofisário. Qual é a alternativa mais adequada?", options: ["É possível excluir o diagnóstico de hipotiroidismo devido aos níveis normais de TSH.", "Para a confirmação do diagnóstico de deficiência de GH é necessária a dosagem do GH basal.", "Trata-se de pan-hipopituitarismo por apresentar deficiência de mais de um setor de hormônios adeno-hipofisários.", "O nível elevado de prolactina descarta o diagnóstico de hipopituitarismo."], correctIndex: 2 },
  { id: "unifesp_2025_025", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Cardiologia", text: "Homem, 70 anos de idade, com diagnóstico de miocardiopatia dilatada por doença de Chagas é admitido no PS por piora da dispneia, ortopneia, dispneia paroxística noturna, edema de membros inferiores bilateralmente até a região escrotal e ganho de peso. Exame físico: sonolência, PA = 90/50 mmHg, FC = 100 bpm em ritmo sinusal, FR = 30 rpm, SpO2 = 90% em ar ambiente, tempo de enchimento capilar = 4 s, ausculta cardíaca com presença de terceira bulha e sopro holossistólico de foco mitral 3+/6+, ausculta pulmonar reduzida em campos médio-inferiores bilateralmente. Qual é o perfil clínico-hemodinâmico da insuficiência cardíaca e a estratégia terapêutica inicial mais adequada?", options: ["Perfil C; furosemida e captopril", "Perfil B; furosemida e captopril", "Perfil B; furosemida, nitroprussiato de sódio e dobutamina", "Perfil C; furosemida e dobutamina"], correctIndex: 3 },
  { id: "unifesp_2025_026", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Geriatria", text: "Mulher, 87 anos de idade, viúva, mora com a filha. A paciente apresenta quadro de perambulação noturna, choro fácil, agressividade verbal. Há 4 anos, apresenta perda de memória recente gradual e lentamente e, há 1 ano, piora da funcionalidade, com necessidade de ajuda para banho, higiene pessoal, alimentação e uso de fraldas. Diante da principal hipótese diagnóstica, quais são as escalas mais indicadas para avaliação do estágio da doença?", options: ["Avaliação Geriátrica Ampla e velocidade de marcha", "Timed Up and Go Test e Clinical Dementia Rating", "Estágio de Avaliação Funcional e Clinical Dementia Rating", "Estágio de Avaliação Funcional e Short Physical Performance Battery"], correctIndex: 2 },
  { id: "unifesp_2025_027", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Infectologia", text: "Homem, 66 anos de idade, portador de doença renal crônica, evoluiu com febre durante sessão de hemodiálise. Foi coletada hemocultura que mostrou crescimento de Staphylococcus aureus resistente à oxacilina. Qual é a opção terapêutica mais adequada para o caso de bacteremia?", options: ["Vancomicina", "Ceftriaxona", "Cefuroxima", "Ampicilina"], correctIndex: 0 },
  { id: "unifesp_2025_028", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Nefrologia", text: "Homem, 27 anos de idade, previamente hígido, foi vítima de acidente automobilístico com sangramentos. Apresenta, à avaliação, PA = 94/52 mmHg, oligúria, creatinina = 1,9 mg/dL (VR 0,7 a 1,3 mg;dL), ureia = 96 mg/dL (VR 20 a 50 mg/dL), K = 6,1 mEq/L (VR 3,5 a 5,1 mEq/L), densidade urinária = 1036 (VR 1005 a 1030), fração de excreção de ureia = 27% e urina I com presença de cilindros hialinos abundantes. Qual é o tratamento mais adequado neste momento?", options: ["Diálise de urgência.", "Reposição de volume.", "Droga inotrópica.", "Furosemida intravenosa."], correctIndex: 1 },
  { id: "unifesp_2025_029", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Medicina Legal", text: "Mulher, 65 anos de idade, é viúva, tem diagnóstico de artrite reumatoide e é atendida em uma UBS. Ela mora com sua filha de 25 anos que não trabalha porque apresenta um quadro de depressão grave. A paciente nunca teve um emprego formal, nunca contribuiu com a Previdência Social e, na última consulta, foi atendida pela assistente social que a orientou a buscar um benefício. Qual é o benefício no qual a paciente se enquadra?", options: ["Aposentadoria por idade", "Benefício de Prestação Continuada", "Aposentadoria por invalidez", "Auxílio doença"], correctIndex: 1 },
  { id: "unifesp_2025_030", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Medicina Intensiva", text: "A sepse é uma disfunção orgânica com risco de morte, causada por uma resposta à infecção. O diagnóstico precoce e o atendimento sistematizado ao paciente séptico têm grande impacto no prognóstico. Qual é a conduta que comprovadamente aumenta a chance de sobrevida do paciente?", options: ["Uso de corticosteroide e expansão de volume na presença de choque séptico", "Administração de antimicrobianos de amplo espectro dirigidos ao foco infeccioso na primeira hora", "Transfusão de concentrado de hemácias para manter a dosagem de hemoglobina acima de 10 g/dL", "Monitorização hemodinâmica invasiva com cateter venoso central, para controle da pressão venosa central e saturação venosa central"], correctIndex: 1 },
  { id: "unifesp_2025_031", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Nefrologia", text: "Mulher, 66 anos de idade, é atendida em consulta de rotina por diabetes tipo 2 e hipertensão arterial. Exame físico: PA = 140/96 mmHg. Exames laboratoriais: taxa de filtração glomerular estimada = 28 mL/min/1,73 m², proteinúria = 1,9 g/24h. Qual é a conduta mais apropriada?", options: ["Prescrever inibidores da enzima conversão da angiotensina ou bloqueadores dos receptores da angiotensina II.", "Evitar bloqueadores do sistema renina-angiotensina devido à função renal diminuída.", "Não iniciar drogas anti-hipertensivas uma vez que a pressão arterial está controlada.", "Iniciar bloqueador de canal de cálcio para diminuir proteinúria."], correctIndex: 0 },
  { id: "unifesp_2025_032", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Medicina Intensiva", text: "Mulher, 70 anos de idade, com histórico de insuficiência cardíaca, foi admitida na UTI com choque cardiogênico após um infarto agudo do miocárdio. Exame físico: PA = 95/60 mmHg, FC = 110 bpm, FR = 25 irpm, SpO2 = 90% com máscara de oxigênio; extremidades frias, pele úmida e distensão jugular. Qual é a escolha mais adequada de agente inotrópico para esta paciente?", options: ["Dopamina", "Noradrenalina", "Dobutamina", "Adrenalina"], correctIndex: 2 },
  { id: "unifesp_2025_033", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Medicina Intensiva", text: "Mulher, 37 anos de idade, é admitida no PS com febre, disúria e lombalgia à direita. Exame físico: paciente torporosa, T = 38,4 °C, tempo de enchimento capilar de 4 segundos, PA = 88/46 mmHg, FC = 108 bpm, FR = 10 irpm, SpO2= 83%. Exames laboratoriais: creatinina = 1,4 mg/dL; sódio = 145 mEq/L; potássio = 4,7 mEq/L; cloro = 105 mmol/L; gasometria arterial com pH = 7,19, pCO2= 40 mmHg, pO2 = 79 mmHg, bicarbonato = 10 mEq/L. Qual é o distúrbio ácido-base observado?", options: ["Acidose respiratória com ânion-gap elevado e resposta metabólica compensatória não adequada", "Equilíbrio ácido-base ajustado com resposta compensatória adequada", "Acidose metabólica com ânion-gap elevado e resposta respiratória compensatória não adequada", "Alcalose respiratória aguda com ânion-gap normal e resposta metabólica adequada"], correctIndex: 2 },
  { id: "unifesp_2025_034", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Reumatologia", text: "Mulher, 28 anos de idade, refere dor e edema em mãos, punhos e tornozelos há 6 meses. Nega outras queixas em outros órgãos ou sistemas. Exame físico: edema e dor à palpação em punhos e articulações metacarpofalângicas bilateralmente. Considerando a principal hipótese diagnóstica, qual dos exames abaixo apresenta melhor valor preditivo positivo para o diagnóstico da doença?", options: ["Fator reumatoide", "FAN", "Anti-CCP", "Proteína C reativa ultrassensível"], correctIndex: 2 },
  { id: "unifesp_2025_035", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Infectologia", text: "Homem, 40 anos de idade, está em tratamento para hanseníase dimorfo-virchowiana há 2 meses com poliquimioterapia multibacilar. Refere, há três dias, \"caroços\" dolorosos na face, tronco e membros, associados a febre de 38,5°C, edema nas mãos e pés, e dor no trajeto dos nervos ulnares bilateralmente. Qual é a conduta mais adequada?", options: ["Suspender o tratamento para a hanseníase e iniciar anti-inflamatórios não hormonais.", "Manter o tratamento para a hanseníase e associar claritromicina.", "Suspender o tratamento para a hanseníase e iniciar metotrexato via oral.", "Manter o tratamento para a hanseníase e iniciar prednisona e talidomida."], correctIndex: 3 },
  { id: "unifesp_2025_036", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Medicina Intensiva", text: "Mulher transgênero, 35 anos de idade, realizou cirurgia plástica há 3 semanas. Procura PS após síncope, dor torácica e dispneia. Faz uso de estrogênio nos últimos 10 anos e há 3 meses trocou para injetável. Exame físico: REG, T = 37,1°C, PA = 90/50 mmHg, FC = 110 bpm, FR = 22 irpm, SpO2 = 94% (ar ambiente). Ausculta pulmonar e cardíaca normais. Considerando a hipótese diagnóstica mais provável, qual é a conduta mais apropriada?", options: ["Angiotomografia de tórax e infusão endovenosa de heparina não fracionada em bomba de infusão continua nas próximas 48h", "Dímero-D e heparina de baixo peso molecular em dose profilática enquanto aguarda o resultado do exame", "Dímero-D, angiotomografia de tórax e heparina de baixo peso molecular em dose plena nas primeiras 48h seguida de anticoagulante de ação direta", "Ecodopplercardiograma e infusão endovenosa de rt-PA em 2h"], correctIndex: 3 },
  { id: "unifesp_2025_037", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Medicina Intensiva", text: "Mulher, 30 anos de idade, previamente hígida, é admitida no PS com dor torácica, expectoração amarelada e febre há cinco dias, apresentando hoje dispneia. Na triagem, foi constatado: PA = 85/40 mmHg, FC = 130 bpm, FR = 28 irpm e SpO2 =85%. A paciente foi levada à sala de emergência. Exames: gasometria arterial pH = 7,23, PaCO2 = 30 mmHg, PaO2 = 55 mmHg, bicarbonato = 16 mEq/L e lactato = 35 mg/L. De acordo com a Campanha de Sobrevivência à Sepse, qual é a alternativa correta?", options: ["Como há insuficiência respiratória, a expansão volêmica deve ser realizada com volumes menores que 30 mL/kg, a fim de se evitar congestão volêmica e piora da dispneia.", "Um vasopressor pode ser iniciado em veia periférica mesmo antes de completar a expansão volêmica, até que se obtenha um acesso venoso profundo.", "Como o paciente não tem choque séptico, devemos esperar os exames para confirmação da hipótese de infecção nas próximas 3 horas, antes de se iniciar antibioticoterapia.", "Como se trata de foco pulmonar, não é necessária a coleta de hemoculturas dada a sua baixa positividade nesse cenário."], correctIndex: 1 },
  { id: "unifesp_2025_038", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pneumologia", text: "Homem, 67 anos de idade, procurou PS com quadro de três dias febre, dor torácica em base direita ventilatório-dependente e tosse produtiva com expectoração esverdeada. Exame físico: REG, orientado, T axilar = 38 °C, PA = 110/70 mmHg, FC = 110 bpm, FR = 32 irpm, SpO2 = 95% em ar ambiente; expansibilidade torácica discretamente diminuída em hemitórax direito; na base direita, observa-se frêmito toracovocal aumentado, som respiratório abolido e broncofonia aumentada. Exames: glicemia = 420 mg/dL; ureia = 70 mg/dL; creatinina = 1,3 mg/dL; TGO = 24 U/L; TGP = 20 U/L; hemograma com 14.000 leucócitos com desvio à esquerda; PCR = 35 mg/dL. Aplique o escore de gravidade CURB-65 e indique o local de tratamento recomendado.", options: ["CURB-65 = 2; tratamento hospitalar.", "CURB-65 = 4; tratamento em unidade de terapia intensiva.", "CURB-65 = 3; tratamento hospitalar.", "CURB-65 = 2; tratamento ambulatorial."], correctIndex: 2 },
  { id: "unifesp_2025_039", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Reumatologia", text: "Mulher, 32 anos de idade, previamente hígida procura pronto atendimento com queixas de poliartralgia migratória de grandes e pequenas articulações há 10 dias, após viagem de férias. No momento refere dor e limitação de movimento em punho direito. Nega trauma e febre. Exame físico: edema, eritema e dor em punho direito. Ultrassom: tenossinovite em punho direito. Considerando o diagnóstico mais provável, qual é a conduta mais adequada?", options: ["Ceftriaxona", "Oxacilina", "Prednisona", "Metotrexato"], correctIndex: 0 },
  { id: "unifesp_2025_040", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Dermatologia", text: "Homem, 28 anos de idade, apresenta lesões de pele há 4 dias, após 10 dias do início do uso de carbamazepina. Exame físico: lesões em alvo atípico na pele, vesículas e bolhas sobre base eritematosa difusa, com áreas de descolamento da pele (total cerca de 10% de pele descolada), erosões na mucosa oral e na glande e eritema conjuntival. Qual é o diagnóstico mais provável?", options: ["Pênfigo vulgar.", "Síndrome de Stevens-Johnson.", "Eritema polimorfo minor.", "Necrólise epidérmica tóxica."], correctIndex: 1 },
  { id: "unifesp_2025_041", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Neurologia", text: "Homem, 63 anos de idade, com histórico de hipertensão arterial crônica e uso ocasional de álcool, é trazido ao PS após sua esposa encontrá-lo caído no chão do banheiro. Ele está confuso, queixando-se de dor de cabeça intensa e apresenta fraqueza no lado direito do corpo. Exame Físico: PA = 190/110 mmHg, FC = 88 bpm; hemiparesia direita e afasia parcial. Não há sinais de trauma externo. Tomografia computadorizada de crânio realizada à admissão: hematoma intracerebral de aproximadamente 40 mL localizado no lobo temporal esquerdo, sem sinais de herniação ou edema cerebral significativo. Qual é a conduta mais adequada, considerando que está dentro de 3 horas do início dos sintomas?", options: ["Controle intensivo da PA nas primeiras 24 horas e controle de temperatura.", "Administração imediata de manitol intravenoso.", "Elevação da cabeceira do leito a 30 graus e controle glicêmico.", "Realização imediata de craniotomia."], correctIndex: 0 },
  { id: "unifesp_2025_043", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Em um estudo randomizado, controlado, que investigou os efeitos da tração controlada do cordão umbilical na terceira fase do trabalho de parto sobre a hemorragia pós-parto, a redução do risco associada à intervenção foi não significante (RR = 0,95; IC95% = 0,79 a 1,15). Com base neste resultado, qual é a alternativa correta?", options: ["O intervalo de confiança de 95% quantifica a imprecisão da amostra em estimar o parâmetro populacional do risco relativo de hemorragia pós-parto.", "Se o tamanho da amostra do estudo fosse aumentado, a largura do intervalo de confiança de 95% aumentaria.", "Um intervalo de confiança de 99% para o risco relativo populacional seria mais estreito do que o intervalo de confiança de 95% apresentado.", "Pode-se inferir que 95% das amostras do grupo de intervenção perderam entre 0,79 e 1,15 vezes mais sangue do que o grupo controle."], correctIndex: 0 },
  { id: "unifesp_2025_044", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Criança, 10 anos de idade, refugiada, é atendida no pronto-socorro apresentando febre e deficiência motora flácida de início súbito. A situação vacinal é ignorada. Considerando a(s) hipótese(s) diagnóstica(s) mais provável(eis), a conduta adequada neste momento, em relação à vigilância epidemiológica, é notificar o caso às autoridades de saúde:", options: ["após resultado positivo da cultura de líquor.", "após resultado positivo da cultura de fezes.", "em até 24 horas após o atendimento.", "após resultado positivo da cultura de fezes e líquor."], correctIndex: 2 },
  { id: "unifesp_2025_045", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Nos anos 90, após a criação do SUS e a partir da luta do movimento indígena, foi regulamentada a Lei Arouca, que instituiu o Subsistema de Atenção à Saúde dos Povos Indígenas (SasiSUS), com o objetivo de garantir aos povos indígenas o acesso à atenção integral à saúde e contemplando a diversidade social, cultural, geográfica, histórica e política. Como é estruturado o atendimento aos povos indígenas dentro do SasiSUS?", options: ["É um sistema de saúde à parte do SUS, gerido pelo Ministério dos Povos Indígenas (MPI) e se organiza em Distritos Sanitários Especiais Indígenas (DSEI) que executam ações de atenção à saúde, saneamento básico, gestão, apoio técnico e apoio ao controle social dos povos indígenas.", "E gerido pela Fundação Nacional dos Povos Indígenas (FUNAI) e organiza o atendimento das populações indígenas por meio de missões periódicas realizadas por equipes multiprofissionais com objetivo de trazer as pessoas doentes para atendimento nos serviços do SUS mais próximos de seus territórios.", "É gerido pelo Ministério dos Povos Indígenas (MPI) e prevê o atendimento das pessoas indígenas nos serviços de atenção primária, secundária, terciária e quaternária destinados à toda população.", "É gerido pela Secretaria de Saúde Indígena (SESAI) e se organiza em Distritos Sanitários Especiais Indígenas (DSEI) que executam ações de atenção à saúde, saneamento básico, gestão, apoio técnico e apoio ao controle social dos povos indígenas."], correctIndex: 3 },
  { id: "unifesp_2025_046", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Um estudo clínico está investigando a eficácia de um novo medicamento para reduzir o risco de determinada doença em pacientes de alto risco. O estudo envolveu 1000 pacientes, divididos igualmente em dois grupos: um grupo recebeu o novo medicamento e o outro grupo recebeu um placebo. Após um ano de acompanhamento, 100 pacientes no grupo do novo medicamento e 250 pacientes no grupo do placebo foram acometidos pela doença. Podemos concluir que a eficácia do novo medicamento foi de:", options: ["30%.", "60%.", "20%.", "40%."], correctIndex: 1 },
  { id: "unifesp_2025_047", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Gestores municipais e estaduais de saúde em todo o país contratam cada vez mais Organizações Sociais de Saúde (OSS) para a gestão de serviços de saúde. Sobre este modelo de gestão, qual é a alternativa correta?", options: ["Entidades privadas, sem fins lucrativos, que atendem aos requisitos da lei, podem ser qualificadas como OSS e receber recursos, bens e servidores públicos para realizar atividades como a gestão de serviços de atenção básica, especializada e hospitalar.", "As OSS relacionam-se com o Poder Público mediante contrato de gestão, conforme definido na lei municipal ou estadual que a instituiu, tendo autonomia para definir o perfil assistencial e o volume de serviços ofertados ao SUS por serem entidades privadas.", "As OSS integram a administração pública e executam tanto serviços assistenciais (atenção básica, especializada e hospitalar), como aqueles que requerem poder de polícia (regulação, controle e avaliação, vigilância sanitária, epidemiológica e ambiental).", "Entidades privadas, com ou sem fins lucrativos, que atendem aos requisitos da lei, podem ser qualificadas como OSS e receber recursos, bens e servidores públicos para realizar a gestão do SUS e de serviços de atenção básica, especializada e hospitalar."], correctIndex: 0 },
  { id: "unifesp_2025_048", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "A notificação de gestantes diagnosticadas com HIV no Sistema de Informação de Agravos de Notificação (SINAN) é uma etapa fundamental para a vigilância epidemiológica, visando o controle da transmissão vertical do vírus. Com base nos protocolos de notificação e seguimento de gestantes com HIV no Brasil, qual das alternativas está correta?", options: ["A notificação de gestantes com HIV deve ser realizada preferencialmente no momento do parto.", "A notificação de gestantes com HIV deve ocorrer tão logo seja feito o diagnóstico, independentemente do trimestre gestacional ou do uso de terapia antirretroviral.", "A notificação é flexibilizada para gestantes com HIV que estejam em terapia antirretroviral e apresentem carga viral indetectável.", "A notificação de casos de gestantes com HIV é dispensável em gestantes que já foram notificadas em gestação anterior."], correctIndex: 1 },
  { id: "unifesp_2025_049", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "O Plano Municipal de Saúde (PMS) constitui-se no instrumento central de planejamento para definição e implementação de todas as iniciativas no âmbito da saúde na gestão municipal do SUS, sendo a base para a execução, acompanhamento e avaliação da gestão do sistema de saúde local para o período de quatro anos. A qual instância o PMS deve ser submetido para apreciação e aprovação?", options: ["Câmara Municipal de Vereadores.", "Conselho Municipal de Saúde.", "Tribunal de Contas do Estado.", "Secretaria Municipal de Saúde."], correctIndex: 1 },
  { id: "unifesp_2025_050", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Medicina de Família", text: "No atendimento dentro da Unidade Básica de Saúde, cada profissional faz um recorte, um destaque de sintomas e informações, de acordo com seu núcleo de conhecimento profissional. A discussão de casos clínicos em equipe, principalmente os mais complexos, é um recurso clínico e gerencial importante. Este modelo corresponde a:", options: ["atenção no modelo biomédico.", "ação de gestão de conflitos.", "clínica ampliada.", "ações de macrogestão."], correctIndex: 2 },
  { id: "unifesp_2025_051", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "O SUS está organizado de forma regionalizada e hierarquizada para formar as Redes de Atenção à Saúde no âmbito de Regiões de Saúde. Qual é o serviço necessário para que um território seja reconhecido como Região de Saúde?", options: ["Centro de alta complexidade em oncologia.", "Centro de Terapia Renal Substitutiva.", "Maternidade de alto risco.", "Unidade Básica de Saúde."], correctIndex: 3 },
  { id: "unifesp_2025_052", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Para determinar se, de fato, um programa de rastreamento de câncer de próstata é benéfico para aumento da longevidade de homens (\"prolongar vidas\"), qual dos seguintes desfechos clínicos é o mais adequado?", options: ["Redução na mortalidade geral.", "Redução na mortalidade específica por câncer de próstata.", "Aumento na sobrevida em 5 anos.", "Redução na taxa de detecção de câncer de próstata metastático."], correctIndex: 0 },
  { id: "unifesp_2025_053", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Você quer diagnosticar hipertensão arterial (PAx140/90 mmHg) e está usando um esfigmomanômetro que, por um defeito, sempre marca 140/90 mmHg ou mais, indicando corretamente as pressões acima destas. Indique o ponto da curva ROC que representa a sensibilidade e a especificidade desse instrumento (o instrumento marca positivo para todos os casos, correspondendo a sensibilidade 100% e especificidade 0%, ponto superior direito da curva).", options: ["I", "IV", "III", "II"], correctIndex: 1 },
  { id: "unifesp_2025_054", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Em um estudo observacional, prospectivo, analítico foi avaliada a relação entre fumar e a incidência de acidente vascular cerebral (AVC) em mulheres com idade entre 30-55 anos, acompanhadas por um período de 10 anos que, no início do estudo, não tinham história de doença coronariana, AVC ou câncer. Os pesquisadores calcularam a incidência de AVC em mulheres fumantes e em mulheres não fumantes, resultando em uma força de associação de 2,8 IC95% (2,4-3,9). Com esse resultado podemos afirmar que:", options: ["Faltou o cálculo do p para afirmarmos que mulheres fumantes possuem 2,8 vezes o risco de ter AVC em relação a mulheres não fumantes.", "Faltou o cálculo do p para afirmarmos que mulheres fumantes possuem 2,8 vezes a chance de ter AVC em relação a mulheres não fumantes.", "Mulheres fumantes possuem 2,8 vezes a chance de ter AVC em relação a mulheres não fumantes.", "Mulheres fumantes possuem 2,8 vezes o risco de ter AVC em relação a mulheres não fumantes."], correctIndex: 3 },
  { id: "unifesp_2025_055", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Endocrinologia", text: "Mulher, 65 anos de idade, faz acompanhamento ambulatorial devido a hipertensão arterial sistêmica há 20 anos, diabetes mellitus tipo 2 há 15 anos, sem outros antecedentes patológicos. Faz uso de anlodipino 10 mg 1x/dia, losartana 50 mg 2x/dia, hidroclorotiazida 25mg 1x/dia, metformina 500 mg 3x/dia, ácido acetil salicílico 100 mg 1x/dia. Queixa-se de edema de membros inferiores iniciado há 3 meses. Exame físico: PA = 118/78 mmHg, edema de membros inferiores +/4, frio, mole, indolor, pulsos cheios e simétricos, panturrilhas livres, sem outras alterações. Exames: hemoglobina glicada = 7,8%, relação albumina/creatinina em amostra isolada de urina = 210 mg/g (VR < 30 mg/g). Considerando efeitos adversos de medicamentos, a renoproteção e a prevenção de eventos cardiovasculares, quais são as condutas mais adequadas?", options: ["Substituir bloqueador do canal de cálcio; iniciar inibidor do cotransportador sódio-glicose 2 (iSGLT2); suspender uso de ácido acetilsalicílico.", "Substituir losartana; iniciar inibidor do cotransportador sódio-glicose 2 (iSGLT2); suspender uso de ácido acetilsalicílico.", "Substituir bloqueador do canal de cálcio; iniciar semaglutida subcutâneo; manter uso de ácido acetilsalicílico.", "Substituir losartana; iniciar semaglutida; suspender uso de ácido acetilsalicílico."], correctIndex: 0 },
  { id: "unifesp_2025_056", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Endocrinologia", text: "Homem, 66 anos de idade, é avaliado em consulta ambulatorial com queixa de prurido na glande, hiperemia local e aumento da produção de esmegma. Trata-se de paciente com antecedente de obesidade, dislipidemia, diabetes mellitus tipo 2, doença renal crônica, estágio 4 A2 filtração glomerular estimada de 28 mL/min/1,73m2 e relação albumina/creatinina em amostra isolada de urina de 200 mg/g (VR < 30 mg/g). Faz uso de metformina 850mg 3x/dia e dapagliflozina 10 mg/dia. Qual é a conduta mais adequada neste momento em relação ao tratamento do diabetes?", options: ["A dapagliflozina deve ser suspensa devido à infecção urogenital.", "A metformina deve ser substituída devido ao risco de acidose lática.", "A metformina deve ser mantida para aumentar a atividade da enzima piruvato carboxilase.", "A dapagliflozina deve ser suspensa devido ao risco de cetoacidose euglicêmica."], correctIndex: 1 },
  { id: "unifesp_2025_057", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "A Força Tarefa Americana para Serviços Preventivos (US Preventive Service Task Force) atualizou sua recomendação para rastreamento de câncer de mama em mulheres, sugerindo mamografias bienais a partir dos 40 anos de idade, ao invés dos 50 anos de idade. Considerando que a prevalência de câncer de mama é menor em mulheres jovens, qual é o impacto esperado desta nova Recomendação na performance do teste diagnóstico?", options: ["A sensibilidade da mamografia será maior.", "A especificidade da mamografia será menor.", "O valor preditivo positivo da mamografia será menor.", "A razão de verossimilhança positiva será menor."], correctIndex: 2 },
  { id: "unifesp_2025_058", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Medicina Legal", text: "A codeína e o tramadol podem ser prescritos em dois tipos de notificação de receitas, segundo a Portaria 344/98. Para decisão do tipo de notificação a ser utilizada lança-se mão dos chamados \"adendos de lista\", os quais preveem os tipos de notificação conforme a unidade posológica e concentração. Sendo assim, quais as notificações de receitas possíveis de serem elaboradas para estes opioides?", options: ["Notificação de Receita A - acima de 100 mg e Notificação de Receita B -psicotrópico - acima de 100 mg.", "Notificação de Receita B - acima de 100 mg e Receituário Sujeito a Controle Especial - abaixo de 100 mg.", "Notificação de Receita B - acima de 100 mg e Notificação de Receita C2 - abaixo de 100 mg.", "Notificação de Receita A - acima de 100 mg e Receituário Sujeito a Controle Especial - abaixo de 100 mg."], correctIndex: 3 },
  { id: "unifesp_2025_059", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Ortopedia", text: "Homem, 63 anos de idade, diabético tipo 2 bem controlado, apresentou queda ao solo há 3 horas, com trauma lateral do quadril direito, evoluindo com dor intensa, encurtamento aparente e rotação externa do membro inferior direito e sem alterações neurovasculares agudas. Qual é a conduta mais adequada?", options: ["Osteossíntese com placa e parafusos.", "Osteossíntese com haste bloqueada intramedular por via retrógrada", "Osteossíntese com parafusos canulados.", "Artroplastia total do quadril."], correctIndex: 3 },
  { id: "unifesp_2025_061", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Durante a epidemia de Zika no nordeste do Brasil, um estudo foi conduzido para investigar a associação entre a infecção congênita pelo vírus Zika e a microcefalia em recém-nascidos. Os pesquisadores selecionaram neonatos com microcefalia e neonatos sem microcefalia. Em seguida, eles investigaram retrospectivamente a exposição materna à infecção pelo vírus Zika confirmada por testes laboratoriais em ambos os grupos. Qual é o desenho de estudo utilizado neste caso?", options: ["Estudo de coorte.", "Ensaio clínico.", "Estudo de caso-controle.", "Estudo transversal."], correctIndex: 2 },
  { id: "unifesp_2025_062", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Neurologia", text: "Mulher, 30 anos de idade, previamente saudável, vem apresentando nos últimos 3 meses quadro progressivo de fraqueza, envolvendo principalmente o segmento craniocervical. Relata engasgos frequentes, voz anasalada e percebe também que no final do dia sua pálpebra direita esta um pouco mais \"caída\" em relação a pálpebra esquerda, além da presença de discreta diplopia, também pior no final do dia. Nega outras doenças ou história familiar de doença neurológica. Nesta situação clínica quais exames seriam os mais adequados a serem solicitados?", options: ["Biopsia muscular com imuno-histoquímica.", "Ressonância magnética de coluna cervical e crânio.", "Eletroneuromiografia e anticorpos anti-receptor de acetilcolina.", "Liquor e bandas oligoclonais."], correctIndex: 2 },
  { id: "unifesp_2025_063", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Genética", text: "Homem, 23 anos de idade, apresenta alta estatura, pectus excavatum, escoliose, aracnodactilia, frouxidão ligamentar, luxação de cristalino em olho esquerdo e discreta dilatação de aorta ascendente. A história familiar revela que sua mãe tem luxação de cristalino bilateral e prolapso da valva mitral, enquanto uma irmã do paciente tem alta estatura, pectus excavatum, escoliose e prolapso da valva mitral. Considerando o diagnóstico mais provável, qual é o padrão de herança implicado nesta condição?", options: ["Herança autossômica recessiva", "Herança autossômica dominante", "Herança mitocondrial", "Herança ligada ao X"], correctIndex: 1 },
  { id: "unifesp_2025_064", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Neurologia", text: "Mulher, 45 anos de idade, hipertensa e diabética dá entrada no pronto-socorro com rebaixamento do nível de consciência há 4 horas. Familiares relatam que ela se queixou de forte cefaleia repentina há 6 horas. Exame oftalmológico: fundo de olho com hemorragia vítrea e subhialoidea. O diagnóstico mais provável é:", options: ["Status Epiléptico", "Hemorragia Subaracnoide", "Tumor em sistema nervoso central", "Coma hiperglicêmico"], correctIndex: 1 },
  { id: "unifesp_2025_065", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Ginecologia", text: "Mulher, 54 anos de idade, refere sangramento genital progressivo há 2 anos. Biopsia endometrial: adenocarcinoma endometrial do tipo seroso. Estudo imuno-histoquímico: expressão anormal para p53. Ressonância Magnética da Pelve: doença restrita ao útero, ausência de linfonodomegalias pélvicas e para-aórticas. Tomografia de abdome superior e tórax: sem alterações. Qual é a conduta mais adequada?", options: ["Histerectomia total com congelação intraoperatória e linfadenectomia pélvica e periaórtica apenas se invasão miometrial maior que 50%.", "Quimioterapia e radioterapia neoadjuvante seguida de histerectomia total e salpingooforectomia bilateral 4 a 6 semanas após.", "Imunoterapia devido mutação de p53 seguido de radioterapia e quimioterapia sistêmica.", "Histerectomia total, salpingooforectomia bilateral, linfadenectomia pélvica bilateral e para-aórtica, omentectomia infra cólica e coleta de lavado peritoneal."], correctIndex: 3 },
  { id: "unifesp_2025_066", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Ginecologia", text: "Mulher, 54 anos de idade, 4G 4Partos normais, refere perda urinária aos grandes esforços (tosse e atividade física) há 3 meses. Nega outras queixas. Ao exame físico observou-se o seguinte POP-Q: Aa=-1 Ba=-1 C=-7 HG=5 CP=2 CVT=10 Ap=-1 Bp=-1 D= -9. Qual é a conduta mais adequada?", options: ["Fisioterapia do assoalho pélvico", "Cirurgia de Burch", "Mirabegrona", "Pessário vaginal em anel"], correctIndex: 0 },
  { id: "unifesp_2025_067", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Ginecologia", text: "Mulher, 48 anos de idade, submeteu-se à histerectomia total abdominal por mioma uterino há 4 meses. Refere ter realizado conização por NIC 3 com margens livres há 8 anos. Segundo as Diretrizes Brasileiras para o rastreamento do câncer do colo do útero a conduta é:", options: ["Descontinuar o exame citológico.", "Realizar pesquisa vaginal de HPV 16.", "Realizar vaginoscopia anual.", "Manter o rastreio colpocitológico trienal."], correctIndex: 3 },
  { id: "unifesp_2025_068", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Ginecologia", text: "Mulher, 44 anos de idade, multípara, realizou a primeira mamografia da vida (quatro incidências básicas) que mostrou mamas lipossubstituídas com presença de calcificações heterogêneas localizadas na região retroareolar da mama esquerda, BI-RADS 0. Qual é o complemento mamográfico adicional necessário para a classificação adequada?", options: ["Compressão localizada", "Incidência craniocaudal exagerada", "Ampliação", "Incidência em perfil absoluto"], correctIndex: 2 },
  { id: "unifesp_2025_069", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Ginecologia", text: "Mulher, 61 anos de idade, refere aumento progressivo e intenso de pelos pelo corpo, queda de cabelos importante, engrossamento da voz e aumento do clitóris há 6 meses. Qual é a hipótese mais provável?", options: ["Tecoma ovariano.", "Tumor da suprarrenal.", "Hipertecose.", "Tumor das células da granulosa."], correctIndex: 2 },
  { id: "unifesp_2025_070", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Ginecologia", text: "Mulher, 26 anos de idade, 3G 3 partos normais, vem ao ambulatório solicitar método contraceptivo. Refere fluxo menstrual abundante com 10 dias de duração acompanhado de cólica menstrual forte nos 3 primeiros dias. Ultrassonografia pélvica: útero com volume 180 mL, presença de nódulo intramural medindo 35x30 mm com distorção do eco endometrial de 10 mm, ovário direito volume 8 mL e ovário esquerdo com cisto simples 20x25 mm e volume 15mL. Qual dos métodos contraceptivos é o mais adequado?", options: ["Injetável com estradiol e medroxiprogesterona.", "DIU liberador de levonorgestrel.", "Pílula com etinilestradiol e ciproterona.", "Pílula com norestisterona."], correctIndex: 0 },
  { id: "unifesp_2025_071", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Ginecologia", text: "Mulher, 41 anos de idade, nuligesta, refere que não menstrua há 8 meses e apresenta ondas de calor eventuais e sudorese noturna duas vezes por mês. Como método contraceptivo utiliza pílula contendo 4mg de drospirenona. Realizou duas coletas sanguíneas com 14 dias de intervalo, respectivamente: 1ª. Coleta FSH= 87 mlU/mL; estradiol= 2 pg/mL e 2ª coleta FSH 61mlU/mL; estradiol 4 pg/mL. Qual é a conduta mais adequada?", options: ["Suspender a drospirenona e observar.", "Prescrever estradiol e progesterona.", "Prescrever isoflavona.", "Encaminhar para coleta de óvulos."], correctIndex: 1 },
  { id: "unifesp_2025_072", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Obstetrícia", text: "Mulher, 32 anos de idade, primigesta, na 12ª semana de gestação, está realizando pré-natal em Unidade Básica de Saúde. Exame físico: PA 120 x 80 mmHg, ausência de edemas. Exame obstétrico: útero aumentado para 12 semanas, batimentos cardíacos fetais = 144 bpm ao sonar. A glicemia de jejum apresenta resultado de 90 mg/dL. Qual é a conduta mais adequada?", options: ["Perfil glicêmico, hemoglobina glicada e avaliação da vitalidade fetal.", "Repetir a glicemia de jejum com 28 semanas e 34 semanas.", "Orientar exercícios físicos e dieta, com glicemia de jejum em 2 semanas.", "Realizar curva glicêmica com 75 g de glicose no segundo trimestre."], correctIndex: 3 },
  { id: "unifesp_2025_073", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Ginecologia", text: "Um casal formado por um homem de 28 anos de idade e uma mulher nuligesta de 27 anos idade, refere 2 anos de tentativas de gestação. Ele, com histórico de uretrite tratada, exame físico sem alterações e espermograma normal. Ela, saudável, com ciclos menstruais regulares, sem queixas de dismenorreia ou dispareunia e com exame físico sem alterações. Qual é o próximo exame na investigação da infertilidade desse casal?", options: ["Avaliação hormonal para ele.", "Ressonância magnética de pelve para ela.", "Histerossalpingografia para ela.", "Cariótipo para ambos."], correctIndex: 2 },
  { id: "unifesp_2025_074", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Obstetrícia", text: "Gestante, 25 anos de idade, apresenta tipagem sanguínea B negativo e o esposo O positivo. Na 21ª semana, após realizar exames laboratoriais de rotina, apresentou pela primeira vez o coombs indireto positivo e com titulação inicial de 11:32, que passou para 1:128 após 3 semanas. Qual é a conduta mais adequada?", options: ["Avaliação do pico sistólico da artéria cerebral média.", "Repetição da pesquisa de anticorpos irregulares em 1 semana.", "Cordocentese e dosagem de hemoglobina.", "Cordocentese e transfusão intrauterina."], correctIndex: 0 },
  { id: "unifesp_2025_075", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Ginecologia", text: "Gestante, 32 anos de idade, III G, IP, idade gestacional de 10 semanas pela DUM, apresentou sangramento vaginal, submetendo-se à curetagem uterina com diagnóstico de abortamento incompleto. O aspecto macroscópico e o resultado do exame histopatológico do material da cavidade uterina é de mola hidatiforme completa. Exames laboratoriais: hCG: 250.000 UI/L antes da curetagem, 50.000 UI/L após 7 dias, 70.000 UI/L após 14 dias e 85.000UI/L após 21 dias do procedimento. Nessa última avaliação, observou-se o aparecimento de lesão arroxeada na parede vaginal posterior, com 2 cm de diâmetro. Qual é a conduta mais adequada?", options: ["Biópsia excisional da lesão vaginal e exame anátomo patológico.", "Nova curetagem uterina e biópsia da lesão vaginal.", "Repetição da dosagem sérica do hCG em 7 dias.", "Estadiamento juntamente com quimioterapia."], correctIndex: 3 },
  { id: "unifesp_2025_076", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Obstetrícia", text: "Secundigesta, 39 anos de idade, 26 semanas, diabética gestacional controlada com dieta, vem à consulta de pré-natal. Hemoglobina de 10,9 g/dL, hematócrito 32%, VCM 78 fL, HCM 25 pg, ferritina 10 ng/mL, eletroforese de hemoglobina normal. Qual é a conduta mais adequada?", options: ["Ferro oral na dose de 30 mg/dia e reavaliação em 8 semanas.", "Ferro oral na dose de 160 a 200 mg/dia e reavaliação em 4 semanas.", "Sacarato de hidróxido de ferro parenteral e reavaliação em 1 semana.", "Aumentar ingestão de ferro na dieta e reavaliação em 8 semanas."], correctIndex: 1 },
  { id: "unifesp_2025_077", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Obstetrícia", text: "Gestante 38 anos, primigesta, com 36 semanas de gestação, com diagnóstico de diabetes mellitus gestacional estabelecido com 13 semanas tendo sido iniciada Insulinização com 25 semanas e desde então vem mantendo cerca de 80 a 85% dos valores do controle glicosimétrico dentro do normal. Exame físico: IMC = 32 Kg/m², altura uterina= 35 cm. Ultrassom: peso estimado = 2890 gramas e o maior bolsão de líquido amniótico: 5 cm. Qual é a conduta mais adequada em relação à resolução da gravidez?", options: ["Cesárea eletiva entre 38 0/7 e 38 6/7 semanas.", "Indução do parto entre 39 0/7 e 39 6/7 semanas.", "Indução do parto entre 37 6/7 e 38 6/7 semanas.", "Cesárea eletiva entre 37 0/7 e 38 0/7 semanas."], correctIndex: 1 },
  { id: "unifesp_2025_078", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Obstetrícia", text: "Mulher 40 anos de idade, IIIG, IP, IIA com o mesmo parceiro. Os abortamentos ocorreram entre 7 e 8 semanas de gestação. Os cariótipos do casal são normais. Exames laboratoriais: anticorpo anticardiolipina IgA = 22 mg/dL que se manteve positivo após 12 semanas de intervalo, mutação em heterozigose G20210 A da protrombina, reação para Citomegalovírus com IgG positivo e IgM negativo. Chega ao pré-natal com 6 semanas de atraso menstrual. Qual é a conduta mais adequada?", options: ["Medicar com aspirina e enoxaparina.", "Orientar seguimento pré-natal rotineiro.", "Medicar com heparina até 42 dias após resolução da gestação.", "Orientar pesquisa de aneuploidia durante a gravidez."], correctIndex: 1 },
  { id: "unifesp_2025_079", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Obstetrícia", text: "Gestante, 36 anos de idade, IG 38 semanas e 3 dias, com gestação gemelar dicoriônica, apresenta diabetes mellitus gestacional. Possui bom controle glicêmico, alcançado com orientação dietética. Exames: taxas de hemoglobina glicada que variaram entre 4,9 e 5,4% e ultrassonografia recente mostrando o feto I em apresentação cefálica e peso estimado no percentil 35, e o feto II em apresentação pélvica e peso estimado no percentil 38 da curva própria para gestação gemelar. Qual é a conduta mais adequada?", options: ["Indução do trabalho de parto.", "Retorno para controle em 7 dias.", "Parto cesáreo.", "Perfil biofísico em dias alternados até 40 semanas."], correctIndex: 0 },
  { id: "unifesp_2025_080", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Obstetrícia", text: "Parturiente de risco habitual, 26 anos de idade, 38 semanas de gestação, primigesta, encontra-se em trabalho de parto espontâneo, sem bloqueio neuraxial. Exame obstétrico: frequência cardíaca fetal basal de 136 batimentos por minuto e com desacelerações precoces repetitivas à cardiotocografia, apresentação cefálica em OP e plano +3 de DeLee. Após 4 horas na fase ativa do período expulsivo, refere estar exausta e não consegue mais realizar puxos. Qual é a conduta mais adequada?", options: ["Hiperoxigenação materna e continuação do período expulsivo.", "Realizar operação cesariana.", "Aplicação de vácuo-extrator ou fórcipe.", "Hidratação materna e tocólise com terbutalina."], correctIndex: 2 },
  { id: "unifesp_2025_081", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Ginecologia", text: "Mulher, 33 anos de idade, nulípara, deseja engravidar. Realizou cirurgia de alta frequencia no colo do útero. Anatomia patológica: neoplasia intraepitelial escamosa de alto grau extensa, com foco de invasão de 4mm, presença de êmbolos carcinomatosos em vasos linfáticos, margens livres para componente invasor e intraepitelial. Qual é a conduta mais adequada?", options: ["Nova cirurgia de alta frequência e reavaliação em 3 meses.", "Liberar para gestação com cerclagem após 6 meses.", "Traquelectomia radical e linfadenectomia pélvica bilateral.", "Realizar cerclagem e liberar para gestação imediatamente."], correctIndex: 2 },
  { id: "unifesp_2025_082", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menina, 4 anos de idade, é contato domiciliar da mãe recentemente diagnosticada com tuberculose pulmonar. A criança está assintomática e apresentou teste tuberculínico de 6 mm. O exame de RX de tórax da criança não apresentou anormalidades. Qual é a conduta mais adequada para essa criança?", options: ["Realizar um novo teste tuberculínico em 3 meses e reavaliar a necessidade de tratamento profilático.", "Não iniciar esquema terapêutico no momento e apenas monitorar a criança, já que está assintomática e com RX normal.", "Iniciar esquema terapêutico completo para tuberculose ativa devido ao contato próximo e alto risco de doença instalada.", "Iniciar isoniazida por 6 meses ou rifampicina por 4 meses e realizar acompanhamento clínico regular."], correctIndex: 3 },
  { id: "unifesp_2025_083", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menino, 7 meses de idade, hígido, foi levado à Unidade Básica de Saúde para atualização vacinal. Ele tinha recebido apenas a vacina para hepatite B ao nascimento. Em relação às vacinas que devem ser administradas, assinale a alternativa correta.", options: ["BCG, pentavalente, pneumocócica 10V, meningocócica C, COVID-19 e influenza, na sazonalidade.", "Pentavalente, pneumocócica 10V, COVID-19, tríplice viral e febre amarela.", "BCG, rotavírus, pentavalente, pneumocócica 10V, meningocócica C, COVID-19, tríplice viral.", "BCG, rotavírus, pentavalente, pneumocócica 10V, meningocócica C, COVID-19, influenza."], correctIndex: 0 },
  { id: "unifesp_2025_084", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menino, 45 dias de vida, há 15 dias apresenta eliminação de fezes com raios de sangue em todas as evacuações. Evacua de 6 a 8 vezes ao dia desde o nascimento e não houve mudança na frequência ou consistência das fezes. Recebe fórmula láctea de partida desde a segunda semana de vida. Não apresenta outros sintomas e não tem alterações ao exame físico. Considerando o diagnóstico mais provável, qual é o mecanismo fisiopatológico envolvido?", options: ["Reação mediada por IgE", "Reação não mediada por IgE", "Deficiência de lactase", "Reação mista"], correctIndex: 1 },
  { id: "unifesp_2025_085", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menino, 7 anos de idade, apresenta queixa de refluxo, queimação retroesternal e dor epigástrica há 1 ano, que não melhoram com uso de inibidor da bomba de prótons. Tem antecedente de alergia à proteína do leite de vaca quando era lactente. Considerando o diagnóstico mais provável, qual é o exame recomendado para a confirmação diagnóstica?", options: ["Cintilografia gastroesofágica com pesquisa de aspiração pulmonar.", "Dosagem de IgE (RAST) para leite de vaca", "Manometria esofágica.", "Endoscopia digestiva alta com biópsias seriadas."], correctIndex: 3 },
  { id: "unifesp_2025_086", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menino, 1 ano e 8 meses de idade, comparece à UBS com história de diarreia por 3 dias com eliminação de vermes nas fezes há 4 dias. Há 1 dia parou de evacuar, apresenta vômitos, dor abdominal; não está aceitando a alimentação e a mãe notou que a criança está com o abdômen inchado e urinando pouco. Qual é a conduta recomendada?", options: ["Encaminhar para serviço de urgência, pois a criança apresenta quadro provável de desidratação e de suboclusão por Ascaris lumbricoides.", "Encaminhar para serviço de urgência, pois a criança apresenta quadro provável de desidratação e gastroenterocolite aguda, presumivelmente infecciosa.", "Iniciar tratamento com mebendazol e soro oral, realizar acompanhamento na UBS e solicitar exame parasitológico de fezes após tratamento.", "Iniciar tratamento com nitazoxanida via oral, acompanhar na UBS e instituir tratamento para todos os familiares."], correctIndex: 0 },
  { id: "unifesp_2025_087", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menino, 10 anos de idade, joga futebol desde pequeno; queixa-se de que há 5 meses vem apresentando dificuldade para correr, há um mês não consegue terminar a partida devido a crises de tosse seca e falta de ar. Há 2 semanas, com resfriado, piorou da tosse, principalmente na madrugada e pela manhã. Tem diagnóstico de rinite alérgica. Qual dos exames abaixo confirma a principal hipótese diagnóstica para sua queixa?", options: ["pHmetria", "Rx de tórax", "Prova de função pulmonar", "IgE específicos para aeroalérgenos"], correctIndex: 2 },
  { id: "unifesp_2025_088", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Lactente de 8 meses, bem nutrido, há 2 meses, desde o início da alimentação complementar, evacua fezes endurecidas e muito calibrosas, a cada 4 a 5 dias, com muito esforço e dor (choro). Mãe aumentou fibra na dieta, sem melhora. Nega atraso de eliminação de mecônio e apresenta exame físico sem alterações. Considerando o diagnóstico mais provável, qual é o tratamento recomendado?", options: ["óleo mineral.", "Probiótico.", "exclusão da proteína do leite de vaca.", "Lactulose."], correctIndex: 3 },
  { id: "unifesp_2025_089", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Ao nascimento, um recém-nascido a termo, filho de mãe multipara com período expulsivo prolongado, estava hipotônico e em apneia. O recém-nascido foi levado à mesa de reanimação sob fonte de calor radiante e foi iniciada a ventilação com balão e máscara e ar ambiente, mas o paciente mantinha-se em apneia e bradicárdico. Após ajuste da técnica da ventilação e aumento da concentração de oxigênio, o recém-nascido não melhorou. Qual é o próximo passo indicado na reanimação?", options: ["Proceder à intubação e iniciar a ventilação com cânula traqueal.", "Prosseguir com a ventilação com máscara facial e iniciar a massagem cardíaca.", "Prosseguir com a ventilação com máscara facial e administrar adrenalina por via intraóssea.", "Proceder à intubação, iniciar a ventilação com cânula traqueal e a massagem cardíaca."], correctIndex: 0 },
  { id: "unifesp_2025_090", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menino, 15 dias de vida, apresentou triagem neonatal positiva para deficiência de G6PD e foi convocado para repetição do exame. Na avaliação pediátrica, a mãe não tem queixas e o exame físico é normal. Qual é a conduta mais adequada neste momento?", options: ["Realizar a nova coleta e orientar o afastamento de desencadeantes de hemólise.", "Solicitar análise molecular do gene G6PD e hemograma para fazer o aconselhamento genético.", "Considerar resultado da primeira coleta como diagnóstico definitivo e afastar desencadeantes de crise.", "Considerar resultado falso positivo e suspender a nova coleta."], correctIndex: 0 },
  { id: "unifesp_2025_091", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menino, 1 ano de idade, iniciou tratamento para hipotireoidismo congênito com 15 dias de vida, sem elucidação etiológica. Apresenta bom crescimento e ganho de peso, além de desenvolvimento neuropsicomotor normal, com dosagens de TSH e hormônios tireoidianos normais e boa aderência ao tratamento. Ultrassonografia de tireoide: glândula tópica de dimensões normais. Segundo o Manual Técnico da Triagem Neonatal Biológica do Ministério da Saúde (2016), qual é a conduta recomendada?", options: ["Realizar cintilografia de tireoide para complementar a investigação etiológica", "Suspender a reposição hormonal e monitorar crescimento e desenvolvimento.", "Reduzir a dose da reposição hormonal em 50% e repetir USG de tireoide em 30 dias.", "Manter reposição hormonal até dois anos de idade."], correctIndex: 3 },
  { id: "unifesp_2025_092", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menina, 7 anos de idade, apresentou artrite em joelho direito há 20 dias com duração de 3 dias, em tornozelo esquerdo há 15 dias com duração de 4 dias e em cotovelo esquerdo há 10 dias com duração de 3 dias. Exame físico: sem sinais de artrite ou outras alterações significativas. A ausculta torácica é normal. Qual é a necessidade de solicitar um ecocardiograma neste caso?", options: ["Para afastar endocardite bacteriana.", "Para afastar aneurisma de coronária.", "Para afastar hipertensão pulmonar.", "Para afastar cardite subclínica."], correctIndex: 3 },
  { id: "unifesp_2025_093", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Recém-nascido (RN) com 28 semanas de idade gestacional, peso de nascimento de 1000g, nasceu vigoroso, mas apresentou desconforto respiratório com 3 minutos de vida, com piora progressiva. Na UTI, RX de tórax apresenta infiltrado reticulogranular. Considerando o diagnóstico mais provável, qual é a conduta recomendada?", options: ["Iniciar ventilação pulmonar invasiva imediatamente.", "Iniciar antibioticoterapia após coleta da hemocultura.", "Iniciar suporte ventilatório com o CPAP nasal.", "Administrar surfactante exógeno apenas se o RN for intubado."], correctIndex: 2 },
  { id: "unifesp_2025_094", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Recém-nascido com 36 semanas de idade gestacional, peso ao nascer de 2850 gramas, filho de mãe secundigesta, hígida, sem intercorrências na gestação, nasceu de parto normal com boa vitalidade. Com 48 horas de vida, está em alojamento conjunto, em aleitamento materno exclusivo, com diurese e evacuação presentes e normais. Exame físico: ictérico zona II, sem outras alterações. Qual é a conduta recomendada?", options: ["Iniciar fototerapia e coletar bilirrubinas em 24 horas para avaliar alta hospitalar.", "Indicar alta hospitalar e reavaliação clínica em 48 horas.", "Indicar alta hospitalar sem necessidade de reavaliação precoce.", "Dosar bilirrubinas para avaliar indicação de fototerapia."], correctIndex: 3 },
  { id: "unifesp_2025_095", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Os pais de Paulo de 7 anos chegam à consulta ambulatorial com os exames do filho que demonstram um quadro sugestivo de leucemia mieloide aguda. Você deverá comunicar o diagnóstico à família. Com base nos principais passos do Protocolo SPIKES de comunicação de más notícias, além de preparar um ambiente privado para conversar com a família, quais seriam suas principais atitudes, em sequência?", options: ["investigar o conhecimento e angústias dos pais; identificar o que eles desejam saber; compartilhar as informações de forma pausada evitando jargões médicos; identificar e acolher as emoções da família; resumir e elaborar um plano de cuidados e acompanhamento com os pais.", "perguntar sobre a história clínica da criança; compartilhar as informações de forma pausada evitando jargões médicos; identificar e conter as emoções da família; resumir e elaborar um plano de cuidados e acompanhamento com os pais.", "identificar o que os pais desejam saber; compartilhar as informações de forma objetiva e breve, evitando jargões médicos; identificar e conter as emoções da família; resumir e elaborar um plano de cuidados e acompanhamento com os pais.", "perguntar sobre a história clínica da criança; compartilhar as informações de forma pausada e empática evitando jargões médicos; ouvir, identificar e conter as emoções da família; estabelecer uma estratégia de conduta e um sumário para os pais."], correctIndex: 0 },
  { id: "unifesp_2025_096", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menino, 15 meses de idade, mantém crescimento abaixo de -2DP (Peso, Estatura e IMC). A família se queixa de baixa aceitação alimentar. Lactente nasceu com 36 semanas de gestação, peso abaixo do Percentil 10 em curvas de crescimento intrauterino, sem intercorrências na evolução neonatal. Mãe fez tratamento para hipotireoidismo na gestação e ultrassom gestacional com 33 semanas identificou oligoidrâmnio. Previsão de estatura final = 167 cm. Exame físico sem alterações. Qual é a conduta mais adequada para a elucidação diagnóstica?", options: ["Dosagens séricas de hormônio do crescimento, IGF-1 e IGFBP-3.", "RX de esqueleto e de mãos e punhos para avaliar a idade óssea.", "Dosagens séricas de T4, TSH e anticorpos antitireoglobulina.", "Exame de urina tipo I, ureia, creatinina e eletrólitos."], correctIndex: 3 },
  { id: "unifesp_2025_097", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menino, 7 anos de idade, é trazido à UBS pela mãe com história de desobediência e agressividade em casa e na escola. Durante a consulta, ele revela sofrer agressões frequentes por parte do pai, inclusive com uso de objetos como cinto e chinelo. Exame fisico: bom estado geral, duas equimoses de 3 cm de diâmetro no dorso, sem outras alterações. A criança parece tranquila na consulta e colabora com o exame. Além de orientar a mãe sobre as consequências da violência, quais as condutas recomendadas para o caso?", options: ["Como as lesões são leves e a criança parece tranquila, não é necessário acompanhamento específico para a situação de violência.", "Comunicar a Delegacia local e o Ministério Público para proteção à criança e eventual destituição do poder familiar por violência.", "Reunir informações, avaliar a família, prosseguir com avaliação social e psicológica e comunicar o Conselho Tutelar da região de moradia.", "Orientar a criança quanto ao seu comportamento agressivo e acompanhar o caso individualmente mantendo sigilo do atendimento."], correctIndex: 2 },
  { id: "unifesp_2025_098", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menino, 7 anos de idade, apresenta baixa estatura, dificuldade de aprendizagem e comportamento hiperativo. Mãe relata uso frequente de álcool durante toda a gestação. Exame físico: fendas palpebrais curtas, hipoplasia de face média, filtro nasolabial apagado e lábio superior fino. Considerando o diagnóstico de transtorno do espectro alcoólico fetal, qual é a alternativa correta?", options: ["Recomenda-se abstinência de bebidas alcoólicas nos dois primeiros trimestres gestacionais, sendo o uso social de álcool permitido no terceiro trimestre de gravidez.", "O álcool atravessa a barreira placentária, contudo não atravessa a barreira hematoencefálica fetal, permitindo o consumo de até 10 gramas semanais.", "Não existe quantidade segura definida para o uso de bebidas alcoólicas na gestação, portanto, a recomendação é abstinência absoluta de álcool durante toda a gravidez.", "Mesmo que a gestante se abstenha de ingerir álcool durante a gravidez, uma história pregressa de uso de bebidas alcoólicas aumenta o risco de desenvolvimento de transtornos do espectro alcoólico fetal."], correctIndex: 2 },
  { id: "unifesp_2025_099", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Recém-nascida (RN) de 7 dias de vida, é levada à UBS para a primeira consulta pediátrica. Sua mãe foi diagnosticada com toxoplasmose aguda no terceiro trimestre da gestação e iniciou tratamento com espiramicina. O USG fetal identificou calcificações intracranianas. O exame físico da RN é normal, o USG transfontanelar não revelou novas lesões além das já detectadas e sua sorologia é IgG positivo e IgM negativo para toxoplasmose. Com base no protocolo de manejo de toxoplasmose congênita, qual é a conduta mais apropriada?", options: ["Iniciar o tratamento com espiramicina e realizar exames mensais de acompanhamento até que a IgM se torne positiva.", "Não iniciar o tratamento neste momento, mas realizar acompanhamento mensal com exames físico, neurológico, sorologia e avaliação oftalmológica.", "Iniciar o tratamento tríplice com pirimetamina, sulfadiazina e ácido folínico por 12 meses, independentemente de novos achados clínicos.", "Repetir a sorologia e ultrassonografia transfontanelar em 15 dias antes de tomar qualquer decisão sobre o início do tratamento."], correctIndex: 2 },
  { id: "unifesp_2025_100", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menino, 5 dias de vida, apresenta icterícia colestática, púrpura, hepatomegalia e esplenomegalia. Emissão otoacústica: resposta ausente bilateral. Tomografia de crânio: atrofia cortical, dilatação ventricular e calcificações periventriculares. Considerando o diagnóstico mais provável, qual exame é o mais recomendado para identificar o agente etiológico da doença?", options: ["Cultura no líquido cefalorraquidiano.", "Cultura no sangue.", "Dosagem de IgM específica.", "PCR na urina."], correctIndex: 3 },
];
